## IO correctness ----
test_that("`snake_to_pascal()` works with correct inputs", {
  result <- snake_to_pascal(c("age_comp", "length_comp", "index"))

  #' @description Test that snake_case strings are converted to PascalCase.
  expect_equal(result, c("AgeComp", "LengthComp", "Index"))

  clear()
})

## Edge handling ----
test_that("`snake_to_pascal()` works with edge cases", {
  result <- snake_to_pascal(character())

  #' @description Test that empty input returns an empty character vector.
  expect_equal(result, character())

  clear()
})

